// Build SMS messages for all major US carrier gateways
const callerName = items[0].json.caller_name || 'there';
const callerPhone = (items[0].json.caller_phone || '').replace(/[\s\-()\+]/g, '');
const callId = items[0].json.call_id || '';
const insuranceType = items[0].json.insurance_type || 'auto';
const toolCallId = items[0].json.toolCallId || '';

// Strip leading '1' if 11 digits (US country code)
let phone10 = callerPhone;
if (phone10.length === 11 && phone10.startsWith('1')) {
  phone10 = phone10.substring(1);
}

if (phone10.length !== 10) {
  return [{
    json: {
      error: true,
      message: 'Invalid phone number: ' + callerPhone + ' (need 10 digits)',
      toolCallId
    }
  }];
}

// Google Form URL for Auto Insurance
const FORM_URL = 'https://docs.google.com/forms/d/1nXAAS4HKmuoofX9dqK5vF_llri1zEEThAyOJBI-midk/viewform';

// SMS body — must be short and clean (SMS = 160 char limit per segment)
const smsBody = `Aloha ${callerName}! Mahalo for calling Equity Insurance. Please complete your ${insuranceType} quote form here: ${FORM_URL} - Call us at (808) 593-7746 with any questions!`;

// US Carrier Email-to-SMS gateways
// We send to ALL major carriers — only the correct one will deliver
const carrierGateways = [
  { carrier: 'ATT',       address: phone10 + '@txt.att.net' },
  { carrier: 'TMobile',   address: phone10 + '@tmomail.net' },
  { carrier: 'Verizon',   address: phone10 + '@vtext.com' },
  { carrier: 'Sprint',    address: phone10 + '@messaging.sprintpcs.com' },
  { carrier: 'USCellular', address: phone10 + '@email.uscc.net' },
  { carrier: 'Cricket',   address: phone10 + '@sms.cricketwireless.net' },
  { carrier: 'MetroPCS',  address: phone10 + '@mymetropcs.com' },
  { carrier: 'Boost',     address: phone10 + '@sms.myboostmobile.com' },
  { carrier: 'GoogleFi',  address: phone10 + '@msg.fi.google.com' }
];

// Combine all gateway addresses into comma-separated TO field
const allRecipients = carrierGateways.map(g => g.address).join(', ');

return [{
  json: {
    to: allRecipients,
    subject: '',
    body: smsBody,
    call_id: callId,
    caller_name: callerName,
    caller_phone: phone10,
    insurance_type: insuranceType,
    form_url: FORM_URL,
    toolCallId,
    error: false,
    gateway_count: carrierGateways.length,
    sent_at: new Date().toISOString()
  }
}];

