// Log the SMS send for follow-up reminder tracking
// Store in workflow static data so WF-08 reminder cron can check
const staticData = $getWorkflowStaticData('global');
const callId = $('Extract Params').item.json.call_id;
const phone = $('Extract Params').item.json.caller_phone;
const sentAt = new Date().toISOString();

if (!staticData.pendingReminders) {
  staticData.pendingReminders = {};
}

// Track this SMS for follow-up reminder (check after 24 hours)
staticData.pendingReminders[callId] = {
  phone,
  caller_name: $('Extract Params').item.json.caller_name,
  insurance_type: $('Extract Params').item.json.insurance_type,
  sent_at: sentAt,
  reminder_sent: false
};

return items;
